      "requirements": [
        {
          "id": "CM-01",
          "description": "Production changes must go through a peer-reviewed pull request with at least one approval before merge.",
          "rationale": "Peer review is Acme PowerSoft's primary control against unreviewed production changes and is required by SOC 2 CC8.1.",
          "relatedCapability": "01KT0XNZEY-Q2TF",
          "requirementMode": "mandatory",
          "naAllowed": false,
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "example": "A committed DecisionRecord naming the repository's required-reviewers policy and the CI/CD pipeline that enforces it."
            }
          ],
          "minimumSatisfactions": 1,
          "validAnswerTypes": [
            "decisionRecord"
          ]
        },
        {
          "id": "CM-02",
          "description": "Emergency changes that bypass standard review must be logged and retroactively reviewed within 2 business days.",
          "rationale": "Emergency changes are sometimes necessary during incidents, but unreviewed changes must not become a permanent escape hatch from CM-01.",
          "relatedCapability": "01KT0XNZEY-Q2TF",
          "requirementMode": "conditional",
          "naAllowed": true,
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "example": "A committed DecisionRecord describing the emergency-change runbook and retroactive review SLA."
            }
          ],
          "minimumSatisfactions": 1,
          "validAnswerTypes": [
            "decisionRecord"
          ]
        }
      ],
