      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"KFP31VBNDB-RART\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Asset & Lease Manager API\",\n  \"description\": \"ASP.NET Core service computing ARO (Asset Retirement Obligation) accretion\\nschedules and managing lease asset records. Publishes lease lifecycle\\nevents to a dedicated Service Bus topic.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"existing-only\",\n  \"primaryTechnologyComponent\": \"12D3W1HAV5-AA70\",\n  \"host\": \"H1ZTZXV5F6-C1CZ\",\n  \"owner\": {\n    \"team\": \"asset-lease\",\n    \"contact\": \"asset-lease@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"runtime-service\",\n    \"asset-lease\"\n  ],\n  \"businessContext\": {\n    \"pillar\": \"business-pillar.asset-management\",\n    \"productFamily\": \"Acme Asset & Lease Manager\"\n  },\n  \"capabilities\": [\n    \"01KT0XNZEY-Q2TF\"\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-K5DR\",\n    \"8SEDYZHP49-YJHQ\",\n    \"KZM0T9NY43-3H8K\"\n  ],\n  \"notes\": {\n    \"serviceAuthentication\": {\n      \"answer\": \"Azure AD B2C via the shared Identity & Access runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"secretsManagement\": {\n      \"answer\": \"Key Vault via the shared Secrets Management runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"serviceLogging\": {\n      \"answer\": \"Forwarded to the shared Observability runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"healthWelfareMonitoring\": {\n      \"answer\": \"Liveness/readiness probes; alerts via shared Observability.\"\n    },\n    \"availabilityModel\": {\n      \"answer\": \"Active-active, 2-4 replicas. 99.5% target.\"\n    },\n    \"scalabilityModel\": {\n      \"answer\": \"Horizontal pod autoscaling on CPU.\"\n    },\n    \"recoverabilityModel\": {\n      \"answer\": \"Stateless; state in the Asset & Lease SQL database and Service Bus topic (at-least-once redelivery).\"\n    },\n    \"failureDomain\": {\n      \"answer\": \"Single AKS cluster, single region -- same regional concentration risk noted for Vantage and Fixed Assets.\"\n    }\n  },\n  \"_source\": \"catalog/runtime-services/asset-lease/rs-asset-lease-manager.yaml\"\n}",
