      "notes": {
        "serviceAuthentication": {
          "answer": "Service-to-service auth to Snowflake and ADLS via managed identity / key-pair auth; no end-user-facing auth since this is batch-only."
        },
        "secretsManagement": {
          "answer": "Snowflake key-pair credentials and connection secrets in Key Vault via the shared Secrets Management runtime service.",
          "satisfiedBy": "relatedObject"
        },
        "serviceLogging": {
          "answer": "Airflow task logs forwarded to the shared Observability runtime service; DAG run history retained in Airflow's own metadata DB.",
          "satisfiedBy": "relatedObject"
        },
        "healthWelfareMonitoring": {
          "answer": "Airflow scheduler liveness probe; DAG SLA-miss alerts routed through shared Observability."
        },
        "availabilityModel": {
          "answer": "Single scheduler instance (Airflow's own HA scheduler mode not yet enabled -- tracked as ticket DATA-212). Worker pool is horizontally scalable."
        },
        "scalabilityModel": {
          "answer": "KubernetesExecutor -- worker pods scale per task, not per replica count."
        },
        "recoverabilityModel": {
          "answer": "DAGs are idempotent and re-runnable; a missed/failed run is recovered by re-triggering, not by infrastructure failover."
        },
        "failureDomain": {
          "answer": "Single AKS cluster, single region. Scheduler is a single point of failure for new DAG runs until DATA-212 lands -- already-running tasks are unaffected."
        }
      },
