      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"66ZW6J2AAH-XSHS\",\n  \"type\": \"data_store_service\",\n  \"name\": \"Tax Fixed Assets Database\",\n  \"description\": \"Azure SQL Managed Instance database backing the Fixed Assets depreciation\\nengine (G4GHBWA8G6-ACY2). Separate from the legacy Property Tax\\nOracle instance -- intentionally not consolidated; the two systems will\\nbe merged or retired together, not piecemeal (see TAX-1142).\\n\",\n  \"version\": \"2022\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"existing-only\",\n  \"primaryTechnologyComponent\": \"TRAS6KGSAC-RGNM\",\n  \"host\": null,\n  \"owner\": {\n    \"team\": \"tax-compliance\",\n    \"contact\": \"tax-compliance@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"data-store-service\",\n    \"tax-compliance\"\n  ],\n  \"businessContext\": {\n    \"pillar\": \"business-pillar.tax-regulatory\",\n    \"productFamily\": \"Acme Tax Suite\"\n  },\n  \"capabilities\": [\n    \"01KQQ4Q026-7T2H\"\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-VBF0\",\n    \"P6M8FWV2D8-0RM8\"\n  ],\n  \"notes\": {\n    \"serviceAuthentication\": {\n      \"answer\": \"Azure AD-integrated auth via managed identity.\"\n    },\n    \"secretsManagement\": {\n      \"answer\": \"No static credentials; managed identity only.\"\n    },\n    \"serviceLogging\": {\n      \"answer\": \"Auditing enabled, forwarded to the shared Observability runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"healthWelfareMonitoring\": {\n      \"answer\": \"Azure-native metrics, alerted via the shared Observability runtime service.\"\n    },\n    \"availabilityModel\": {\n      \"answer\": \"Zone-redundant Managed Instance, automatic failover.\"\n    },\n    \"scalabilityModel\": {\n      \"answer\": \"Vertical scaling only; no current read-replica need.\"\n    },\n    \"recoverabilityModel\": {\n      \"answer\": \"Automated backups, 35-day retention, point-in-time restore.\"\n    },\n    \"backup\": {\n      \"answer\": \"Azure-managed automated backups.\"\n    },\n    \"ha\": {\n      \"answer\": \"Zone-redundant with automatic failover.\"\n    },\n    \"encryption\": {\n      \"answer\": \"Transparent Data Encryption at rest, TLS in transit.\"\n    },\n    \"accessControl\": {\n      \"answer\": \"Azure AD-only; private endpoint, no public network access.\"\n    }\n  },\n  \"_source\": \"catalog/data-store-services/tax-compliance/ds-tax-sqldb.yaml\"\n}",
