      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"4FV0S214EX-N14E\",\n  \"type\": \"software_deployment_pattern\",\n  \"name\": \"Acme Admin Console Pattern\",\n  \"description\": \"Deployment pattern for the internal Acme Admin Console: containerized\\nNext.js app on the shared AKS baseline, no independent data store (reads/\\nwrites through the Vantage Entitlement API), internal-staff-only access.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"existing-only\",\n  \"owner\": {\n    \"team\": \"infra-devops\",\n    \"contact\": \"infra-devops@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"software-deployment-pattern\",\n    \"infra-devops\",\n    \"internal-tool\"\n  ],\n  \"businessContext\": {\n    \"pillar\": \"business-pillar.platform\",\n    \"productFamily\": \"Acme Admin Console\"\n  },\n  \"notes\": {\n    \"availabilityTarget\": \"99% (internal tool, business-hours usage)\",\n    \"availabilityRequirement\": \"Active-active, fixed 2 replicas.\",\n    \"dataClassification\": \"Internal\",\n    \"failureDomain\": {\n      \"scope\": \"single-region\",\n      \"description\": \"Single AKS cluster, single region. Lower-impact blast radius than customer-facing products -- support staff lose tooling, customers are unaffected.\"\n    },\n    \"patternDeviations\": \"Lower availability/scalability bar than every other SDP, by design -- see the requirement-group-rigor discussion in ONBOARDING.md.\",\n    \"deploymentTargets\": \"Shared AKS baseline, East US 2.\",\n    \"interServiceConnections\": \"All data access proxied through the Vantage Entitlement API; no direct database connection of its own.\",\n    \"externalDependencies\": \"Azure AD B2C, Azure Key Vault, Datadog.\"\n  },\n  \"decisionRecords\": [\n    {\n      \"ref\": \"T7HDN1C4Y6-N0E3\",\n      \"key\": \"noApplicablePattern\"\n    }\n  ],\n  \"networkZones\": [\n    {\n      \"id\": \"app\",\n      \"name\": \"Application\",\n      \"tier\": \"application\",\n      \"description\": \"AKS-hosted admin console pods, restricted to internal-staff Azure AD app role.\"\n    }\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Application\",\n      \"deploymentTarget\": \"H1ZTZXV5F6-C1CZ\",\n      \"deployableObjects\": [\n        {\n          \"ref\": \"DDKF51GRXT-9VE9\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"application\",\n          \"intent\": \"ha\",\n          \"notes\": \"Fixed 2 replicas, no autoscaling.\"\n        },\n        {\n          \"ref\": \"ZV0QNH8M3D-EYW8\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"application\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Identity & Access service, internal-staff app role.\"\n        },\n        {\n          \"ref\": \"37AJ772M7W-V27N\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"utility\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Secrets Management service.\"\n        },\n        {\n          \"ref\": \"FH8VD6HQ69-ZMEG\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"utility\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Observability service.\"\n        }\n      ]\n    }\n  ],\n  \"_source\": \"catalog/engineering/software-deployment-patterns/infra-devops/sdp.yaml\"\n}",
