      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"37MYJCZ1V9-439T\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Tenant Entitlement Cache (Azure Cache for Redis)\",\n  \"description\": \"Caching tier in front of the Acme Vantage entitlement database. Not part of the Admin agent's original shared-services list -- added during Core Platform's review of the draft catalog (see EXERCISE_REPORT.md Agent Disposition Log).\\n\",\n  \"version\": \"1.0.0\",\n  \"deliveryModel\": \"paas\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"core-platform\",\n    \"contact\": \"core-platform@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"runtime\",\n    \"caching\",\n    \"shared-service\"\n  ],\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"A4M2HB1G1D-22DT\",\n  \"notes\": {\n    \"serviceAuthentication\": \"Access key authentication scoped to the Vantage entitlement service's managed identity via Azure AD-based Redis authentication (no shared access keys distributed to other teams).\",\n    \"secretsManagement\": \"Connection string is not a static secret -- Azure AD token-based auth means no long-lived Redis password exists for this instance.\",\n    \"serviceLogging\": \"Cache hit/miss ratio and eviction events stream to Datadog via the Azure Cache for Redis diagnostic integration.\",\n    \"healthWelfareMonitoring\": \"Datadog Redis integration tracks memory pressure, hit ratio, and connected client count.\",\n    \"availabilityModel\": \"Premium tier with zone redundancy in East US 2; tracked against Microsoft's 99.9% Redis SLA.\",\n    \"scalabilityModel\": \"Vertical scaling reviewed quarterly against memory pressure metrics; clustering not yet enabled (entitlement dataset fits comfortably in a single shard today).\",\n    \"recoverabilityModel\": \"Cache is rebuildable from the Vantage Postgres system of record on cold start; no backup is taken because the cache holds no data that is not also durably stored elsewhere.\",\n    \"failureDomain\": \"A cache outage degrades entitlement-check latency (falls back to direct Postgres reads) but does not cause incorrect entitlement decisions or downtime.\",\n    \"externalInteractionRationales\": {},\n    \"internalComponentRationales\": {}\n  },\n  \"internalComponents\": [\n    {\n      \"ref\": \"A4M2HB1G1D-22DT\",\n      \"role\": \"function\"\n    }\n  ],\n  \"externalInteractions\": [\n    {\n      \"name\": \"Service Monitoring\",\n      \"notes\": \"Hit ratio and memory pressure alerts routed through the shared Observability runtime service.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-98VD\"\n      ]\n    }\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-K5DR\",\n    \"KZM0T9NY43-3H8K\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"RATHKFJREJ-J2QN\",\n      \"key\": \"availabilityModel\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"KZM0T9NY43-3H8K\",\n      \"requirementId\": \"SLA-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"availabilityModel\",\n      \"ref\": \"RATHKFJREJ-J2QN\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/rs-caching.yaml\"\n}",
      "existsInCatalog": true,
      "outboundRelationships": [],
      "inboundRelationships": []
