      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"0XWT91WY2F-2RR4\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Messaging Backbone (Azure Service Bus)\",\n  \"description\": \"Cross-product asynchronous event backbone owned by Infra & DevOps on behalf of all product teams.\",\n  \"version\": \"1.0.0\",\n  \"deliveryModel\": \"paas\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"infra-devops\",\n    \"contact\": \"infra-devops@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"runtime\",\n    \"messaging\",\n    \"shared-service\"\n  ],\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"VKSQHZCHTK-VJP1\",\n  \"notes\": {\n    \"serviceAuthentication\": \"Producers and consumers authenticate via Azure AD workload identity (managed identity per AKS pod); no shared access signature keys are distributed to application code.\",\n    \"secretsManagement\": \"No long-lived secrets exist for this service; managed identity tokens are short-lived and issued by Azure AD.\",\n    \"serviceLogging\": \"Operational logs (throttling, dead-letter events) stream to Datadog via the Azure Service Bus diagnostic settings integration.\",\n    \"healthWelfareMonitoring\": \"Datadog Azure Service Bus integration tracks queue depth, dead-letter count, and active connection count per topic.\",\n    \"availabilityModel\": \"Premium tier with availability zone redundancy in East US 2; tracks Microsoft's 99.9% Service Bus Premium SLA.\",\n    \"scalabilityModel\": \"Messaging units scaled manually today based on quarterly throughput review; auto-scale evaluation tracked under DEVOPS-211.\",\n    \"recoverabilityModel\": \"Geo-disaster recovery paired namespace in Central US, manual failover initiated by Infra & DevOps on-call per RUNBOOK-SB-02.\",\n    \"failureDomain\": \"A regional outage affects all cross-product event delivery; producers buffer locally for up to 5 minutes before failing the originating request.\",\n    \"externalInteractionRationales\": {},\n    \"internalComponentRationales\": {}\n  },\n  \"internalComponents\": [\n    {\n      \"ref\": \"VKSQHZCHTK-VJP1\",\n      \"role\": \"function\"\n    }\n  ],\n  \"externalInteractions\": [\n    {\n      \"name\": \"Service Monitoring\",\n      \"notes\": \"Queue depth and dead-letter alerts routed through the shared Observability runtime service.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-98VD\"\n      ]\n    }\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-K5DR\",\n    \"1JGV5Y25KN-73W7\",\n    \"KZM0T9NY43-3H8K\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"EZ5M2Q77AG-1SEB\",\n      \"key\": \"recoverabilityModel\"\n    },\n    {\n      \"ref\": \"DQ7CFFDSYG-31SG\",\n      \"key\": \"availabilityModel\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"1JGV5Y25KN-73W7\",\n      \"requirementId\": \"DR-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"recoverabilityModel\",\n      \"ref\": \"EZ5M2Q77AG-1SEB\"\n    },\n    {\n      \"requirementGroup\": \"KZM0T9NY43-3H8K\",\n      \"requirementId\": \"SLA-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"availabilityModel\",\n      \"ref\": \"DQ7CFFDSYG-31SG\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/rs-messaging-backbone.yaml\"\n}",
