      "notes": {
        "serviceAuthentication": "Access to each product's vault is scoped by Azure RBAC to that product's AKS workload identity and to the Infra & DevOps break-glass admin group; no application uses a vault access policy with broad permissions.",
        "secretsManagement": "This is itself the company's secrets management service; vault master access is the one credential not stored in another vault, and is split-knowledge protected per RUNBOOK-SEC-01.",
        "serviceLogging": "Vault access logs (every Get/Set/Delete on a secret) stream to Datadog via Key Vault diagnostic settings, satisfying AU-01 for secret access specifically.",
        "healthWelfareMonitoring": "Datadog Azure Key Vault integration alerts on throttling and on any access from outside the expected AKS workload identity set.",
        "availabilityModel": "Premium (HSM-backed) tier with zone redundancy in East US 2; tracked against Microsoft's 99.99% Key Vault SLA.",
        "scalabilityModel": "Vendor-managed; no scaling action required by Acme PowerSoft.",
        "recoverabilityModel": "Soft-delete and purge protection enabled on every vault (90-day retention); vault contents also captured in the quarterly DR-01 recovery test for each dependent product.",
        "failureDomain": "An outage blocks new secret retrieval; already-cached secrets in running pods continue to function until pod restart, bounding blast radius to new deployments and pod restarts only.",
        "externalInteractionRationales": {},
        "internalComponentRationales": {}
      },
