      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"Z3CAV76ED8-7XEV\",\n  \"type\": \"data_store_service\",\n  \"name\": \"Acme Insight Hub Data Warehouse (Snowflake)\",\n  \"description\": \"Consolidated cross-product analytics warehouse fed by per-product ELT pipelines and serving forecasting model training data and BI queries.\",\n  \"version\": \"1.0.0\",\n  \"deliveryModel\": \"saas\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"data-analytics\",\n    \"contact\": \"data-analytics@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"data-at-rest\",\n    \"shared-service\"\n  ],\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"6YWAMCXE87-H8JW\",\n  \"notes\": {\n    \"serviceAuthentication\": \"Analysts and pipeline service accounts authenticate via Azure AD SSO federated into Snowflake (SCIM-provisioned roles); no native Snowflake passwords are issued.\",\n    \"secretsManagement\": \"Pipeline service account key pairs are stored in the Infra & DevOps Key Vault and rotated every 180 days by an Airflow-triggered rotation job.\",\n    \"serviceLogging\": \"Snowflake's ACCOUNT_USAGE query history and login history are exported nightly into a dedicated audit schema and forwarded to Datadog log management.\",\n    \"healthWelfareMonitoring\": \"Datadog Snowflake integration tracks warehouse credit consumption, query queueing, and failed-login spikes.\",\n    \"availabilityModel\": \"Snowflake's standard multi-cluster, multi-AZ architecture within the Azure East US 2 region; tracked against Snowflake's published Enterprise SLA.\",\n    \"scalabilityModel\": \"Multi-cluster warehouse auto-scaling enabled for the BI consumption warehouse; the ELT load warehouse scales vertically only, reviewed quarterly against the cost budget.\",\n    \"recoverabilityModel\": \"Snowflake Time Travel (7-day) plus a weekly Fail-safe-backed database clone exported to a separate Snowflake account in a different Azure region for catastrophic-loss recovery.\",\n    \"failureDomain\": \"A Snowflake outage stops new ELT loads and BI queries but does not affect any product's operational database -- this is purely an analytics-tier dependency, not a transactional one.\",\n    \"backup\": {\n      \"strategy\": \"Snowflake Time Travel (7 days) plus weekly cross-region database clone.\",\n      \"rto\": \"4 hours for cross-region clone restore\",\n      \"rpo\": \"24 hours (last successful nightly clone)\"\n    },\n    \"ha\": {\n      \"mechanism\": \"Snowflake-managed multi-cluster warehouse with automatic cluster failover within region.\"\n    },\n    \"encryption\": {\n      \"atRest\": \"AES-256, Snowflake-managed keys (Tri-Secret Secure not yet enabled -- tracked under DATA-088).\"\n    },\n    \"accessControl\": {\n      \"model\": \"Role-based access control (RBAC) mapped from Azure AD group membership via SCIM; least-privilege roles per product schema.\"\n    },\n    \"externalInteractionRationales\": {},\n    \"internalComponentRationales\": {}\n  },\n  \"internalComponents\": [\n    {\n      \"ref\": \"6YWAMCXE87-H8JW\",\n      \"role\": \"function\"\n    }\n  ],\n  \"externalInteractions\": [\n    {\n      \"name\": \"Backup Platform\",\n      \"notes\": \"Weekly cross-region database clone to a secondary Snowflake account, orchestrated by an Airflow DAG.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-7T2H\"\n      ]\n    }\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-VBF0\",\n    \"1JGV5Y25KN-73W7\",\n    \"8SEDYZHP49-YJHQ\",\n    \"P6M8FWV2D8-0RM8\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"5T6Z38JS60-H8WK\",\n      \"key\": \"recoverabilityModel\"\n    },\n    {\n      \"ref\": \"8KB6TBR17C-FG0W\",\n      \"key\": \"ha\"\n    },\n    {\n      \"ref\": \"AY0FN501VQ-9SYT\",\n      \"key\": \"serviceAuthentication\"\n    },\n    {\n      \"ref\": \"5TE793A7E9-NKME\",\n      \"key\": \"serviceLogging\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"1JGV5Y25KN-73W7\",\n      \"requirementId\": \"DR-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"recoverabilityModel\",\n      \"ref\": \"5T6Z38JS60-H8WK\"\n    },\n    {\n      \"requirementGroup\": \"1JGV5Y25KN-73W7\",\n      \"requirementId\": \"DR-02\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"ha\",\n      \"ref\": \"8KB6TBR17C-FG0W\"\n    },\n    {\n      \"requirementGroup\": \"8SEDYZHP49-YJHQ\",\n      \"requirementId\": \"AC-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"serviceAuthentication\",\n      \"ref\": \"AY0FN501VQ-9SYT\"\n    },\n    {\n      \"requirementGroup\": \"P6M8FWV2D8-0RM8\",\n      \"requirementId\": \"AU-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"serviceLogging\",\n      \"ref\": \"5TE793A7E9-NKME\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/data-store-services/ds-data-warehouse.yaml\"\n}",
