      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"G5XV9MK4RH-RG0A\",\n  \"type\": \"network_service\",\n  \"name\": \"Platform API Gateway (Azure API Management)\",\n  \"description\": \"Single ingress point for every Acme PowerSoft product API. Enforces authentication (delegated to Identity & Access), per-tenant rate limiting, and request/response transformation so product teams do not each implement their own gateway layer.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"core-platform\",\n    \"contact\": \"core-platform@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"network-service\",\n    \"api-gateway\",\n    \"shared-service\"\n  ],\n  \"deliveryModel\": \"paas\",\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"MH7JS0SPA4-YA23\",\n  \"vendor\": \"Microsoft\",\n  \"productName\": \"Azure API Management\",\n  \"productVersion\": \"Premium v2\",\n  \"networkFunction\": \"API gateway -- inbound request routing, authentication enforcement, per-tenant rate limiting, and response transformation for every product API.\",\n  \"networkTopology\": \"Sits in the perimeter zone in front of each product's AKS ingress; all inbound product traffic from the public internet and from Acme's customer-facing web apps passes through this gateway before reaching any product runtime service.\",\n  \"protocols\": [\n    \"HTTPS\",\n    \"WebSocket (Insight Hub streaming endpoints only)\"\n  ],\n  \"notes\": {\n    \"placementContext\": \"Perimeter zone -- the only network service in the catalog with direct public internet exposure.\",\n    \"requirementContext\": \"Service Level Baseline (SLA-01/SLA-02) and Access Control Baseline (AC-01/AC-02) both apply because this is the shared ingress for every customer-facing product.\"\n  },\n  \"decisionRecords\": [],\n  \"internalComponents\": [\n    {\n      \"ref\": \"MH7JS0SPA4-YA23\",\n      \"role\": \"gateway\"\n    }\n  ],\n  \"requirementGroups\": [\n    \"01KSWVZSZ5-B146\",\n    \"8SEDYZHP49-YJHQ\",\n    \"KZM0T9NY43-3H8K\"\n  ],\n  \"_source\": \"catalog/shared-services/network-services/rs-api-gateway.yaml\"\n}",
