      "requirements": [
        {
          "id": "function",
          "description": "What capability does this SaaS service provide?",
          "rationale": "Capability is the core architectural reason the service exists.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "capabilities",
              "example": "capabilities: [waf]"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "data-boundary",
          "description": "Does data leave the infrastructure boundary through this service?",
          "rationale": "The data boundary determines whether the service is modeled as SaaS and what governance obligations follow.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "vendorGovernance.dataLeavesInfrastructure",
              "example": "vendorGovernance: {dataLeavesInfrastructure: true}"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "data-residency",
          "description": "What are the vendor's data residency commitments? Critical for FERPA, HIPAA-adjacent, and PII data.\n",
          "rationale": "Data residency commitments are required before regulated or sensitive workloads can depend on a blackbox vendor platform.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "vendorGovernance.dataResidencyCommitment",
              "example": "vendorGovernance: {dataResidencyCommitment: US-only}"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "data-processing-agreement",
          "description": "Is a Data Processing Agreement in place with this vendor?",
          "rationale": "A SaaS dependency that handles organizational data requires explicit contractual treatment.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "vendorGovernance.dpaNotes",
              "example": "vendorGovernance: {dpaNotes: DPA signed 2024-03, covers FERPA and COPPA}"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "compliance-certifications",
          "description": "What compliance certifications does the vendor carry?",
          "rationale": "Blackbox services need external attestations or certifications when internal architecture evidence is unavailable.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "complianceCerts",
              "allowEmpty": true,
              "example": "complianceCerts: [SOC2 Type II, ISO27001]"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "authentication-model",
          "description": "How does the organization authenticate to this service?",
          "rationale": "SaaS consumption must define how identities are established and federated into the vendor platform.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "authenticationModel",
              "example": "authenticationModel: saml"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "audit-visibility",
          "description": "What logging, audit, or event visibility does the consumer have into this service?",
          "rationale": "Blackbox services must still define what operational and security evidence is visible to the adopter.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "key": "auditVisibility",
              "example": "A committed DecisionRecord, referenced from decisionRecords with key: auditVisibility, recording this decision (or why it is not applicable)."
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "decisionRecord"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "health-status-visibility",
          "description": "How can the consumer observe the health, status, or incident state of this service?",
          "rationale": "Vendor-managed services require an explicit answer for how outages or degradations are detected by the adopter.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "vendorGovernance.incidentNotificationProcess",
              "example": "vendorGovernance: {incidentNotificationProcess: Vendor status page plus email incident notifications}"
            },
            {
              "mechanism": "decisionRecord",
              "key": "healthStatusVisibility",
              "example": "A committed DecisionRecord, referenced from decisionRecords with key: healthStatusVisibility, recording this decision (or why it is not applicable)."
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "decisionRecord",
            "field"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "failure-domain",
          "description": "What is the failure domain of this SaaS dependency?",
          "rationale": "Shared vendor dependencies can create large failure domains and that scope must be explicit.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "key": "failureDomain",
              "example": "A committed DecisionRecord, referenced from decisionRecords with key: failureDomain, recording this decision (or why it is not applicable)."
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "decisionRecord"
          ],
          "minimumSatisfactions": 1
        },
        {
          "id": "vendor-sla",
          "description": "What is the vendor's SLA commitment?",
          "rationale": "SaaS service quality must be defined in terms available to the adopter, not hidden internal design.",
          "canBeSatisfiedBy": [
            {
              "mechanism": "field",
              "key": "vendorGovernance.vendorSLA",
              "example": "vendorGovernance: {vendorSLA: 99.99% uptime, 24x7 support}"
            }
          ],
          "requirementMode": "mandatory",
          "naAllowed": false,
          "validAnswerTypes": [
            "field"
          ],
          "minimumSatisfactions": 1
        }
      ],
