      "requirements": [
        {
          "id": "AC-01",
          "description": "Administrative access to this service must use named individual accounts with multi-factor authentication. Shared or service-account interactive logins are not permitted.",
          "rationale": "Named, MFA-protected accounts are required to attribute administrative actions to an individual and to meet SOC 2 CC6.1 access control expectations.",
          "relatedCapability": "01KQQ4Q026-4JR6",
          "requirementMode": "mandatory",
          "naAllowed": false,
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "key": "serviceAuthentication"
            },
            {
              "mechanism": "decisionRecord",
              "example": "A committed DecisionRecord describing an access model exception and its compensating control."
            }
          ],
          "minimumSatisfactions": 1,
          "validAnswerTypes": [
            "decisionRecord",
            "decisionRecord"
          ]
        },
        {
          "id": "AC-02",
          "description": "Access to this service must be reviewed at least quarterly, and access must be de-provisioned within 24 hours of a role change or termination.",
          "rationale": "Periodic access review and prompt de-provisioning are required by SOC 2 CC6.2/CC6.3 and reduce the window in which stale credentials can be misused.",
          "relatedCapability": "01KQQ4Q026-4JR6",
          "requirementMode": "mandatory",
          "naAllowed": false,
          "canBeSatisfiedBy": [
            {
              "mechanism": "decisionRecord",
              "example": "A committed DecisionRecord naming the access review cadence and the de-provisioning automation or runbook used."
            }
          ],
          "minimumSatisfactions": 1,
          "validAnswerTypes": [
            "decisionRecord"
          ]
        }
      ],
