      "requirements": [
        {
          "id": "VM-01",
          "description": "Every technology component running in production must have a documented patch cadence and must not be past its vendor's end-of-life or end-of-extended-support date.",
          "rationale": "Unpatched and unsupported software is Acme PowerSoft's single largest source of audit findings; this control makes vendor lifecycle status a first-class, queryable field rather than tribal knowledge.",
          "relatedCapability": "01KQQ4Q026-BH6E",
          "requirementMode": "mandatory",
          "naAllowed": false,
          "canBeSatisfiedBy": [
            {
              "mechanism": "technologyComponentConfiguration",
              "criteria": {
                "field": "vendorLifecycle"
              },
              "example": "A TechnologyComponent record with vendorLifecycle.mainstreamSupportEnd/extendedSupportEnd populated and not in the past."
            },
            {
              "mechanism": "decisionRecord",
              "example": "A committed DecisionRecord documenting an accepted-risk exception for a component past end-of-life, with a remediation date."
            }
          ],
          "minimumSatisfactions": 1,
          "validAnswerTypes": [
            "technologyComponentConfiguration",
            "decisionRecord"
          ]
        }
      ],
