      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"G4GHBWA8G6-ACY2\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Tax Fixed Assets Depreciation Engine\",\n  \"description\": \"Modern ASP.NET Core service computing book/tax depreciation schedules\\nfor the Fixed Assets module. Containerized, deployed to AKS -- unlike\\nits Property Tax sibling, this one fits the schema cleanly.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"existing-only\",\n  \"primaryTechnologyComponent\": \"12D3W1HAV5-AA70\",\n  \"host\": \"H1ZTZXV5F6-C1CZ\",\n  \"owner\": {\n    \"team\": \"tax-compliance\",\n    \"contact\": \"tax-compliance@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"runtime-service\",\n    \"tax-compliance\"\n  ],\n  \"businessContext\": {\n    \"pillar\": \"business-pillar.tax-regulatory\",\n    \"productFamily\": \"Acme Tax Suite\"\n  },\n  \"capabilities\": [\n    \"01KT0XNZEY-Q2TF\"\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-K5DR\",\n    \"8SEDYZHP49-YJHQ\",\n    \"KKDJGX6P7C-N9AR\"\n  ],\n  \"notes\": {\n    \"serviceAuthentication\": {\n      \"answer\": \"Azure AD B2C via the shared Identity & Access runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"secretsManagement\": {\n      \"answer\": \"Connection strings in Key Vault via the shared Secrets Management runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"serviceLogging\": {\n      \"answer\": \"Forwarded to the shared Observability runtime service.\",\n      \"satisfiedBy\": \"relatedObject\"\n    },\n    \"healthWelfareMonitoring\": {\n      \"answer\": \"Liveness/readiness probes; alerts via the shared Observability runtime service.\"\n    },\n    \"availabilityModel\": {\n      \"answer\": \"Active-active, 2-6 replicas. 99.5% target -- one tier below Vantage since this isn't a hard dependency for other products.\"\n    },\n    \"scalabilityModel\": {\n      \"answer\": \"Horizontal pod autoscaling on CPU.\"\n    },\n    \"recoverabilityModel\": {\n      \"answer\": \"Stateless; state lives in the Tax Fixed Assets SQL database.\"\n    },\n    \"failureDomain\": {\n      \"answer\": \"Single AKS cluster, single region. Same regional concentration risk as Vantage.\"\n    }\n  },\n  \"_source\": \"catalog/runtime-services/tax-compliance/rs-tax-fixed-assets.yaml\"\n}",
