      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"NDHCZF14QX-4EVH\",\n  \"type\": \"software_deployment_pattern\",\n  \"name\": \"Acme RegTrack Pattern\",\n  \"description\": \"Deployment pattern for RegTrack: containerized Cost of Service engine on\\nthe shared AKS baseline, Azure SQL Database for rate-case records, and a\\nPower BI Embedded capacity serving the rate-case dashboard to regulators\\nand outside counsel.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"existing-only\",\n  \"owner\": {\n    \"team\": \"regulatory\",\n    \"contact\": \"regulatory@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"software-deployment-pattern\",\n    \"regulatory\"\n  ],\n  \"businessContext\": {\n    \"pillar\": \"business-pillar.tax-regulatory\",\n    \"productFamily\": \"Acme RegTrack\"\n  },\n  \"notes\": {\n    \"availabilityTarget\": \"99.5% (engine) / Microsoft SLA, not independently modeled (Power BI Embedded)\",\n    \"availabilityRequirement\": \"Active-active AKS pods, zone-redundant SQL Database.\",\n    \"dataClassification\": \"Confidential\",\n    \"failureDomain\": {\n      \"scope\": \"single-region\",\n      \"description\": \"Same single-region AKS concentration risk as other Azure-AD-B2C-fronted products.\"\n    },\n    \"patternDeviations\": \"Long-term (10-year) evidentiary record retention and external (outside counsel) read access are both handled by processes with no representation in this catalog's object model. See commit history for the two flagged Schema Completeness gaps.\",\n    \"deploymentTargets\": \"Shared AKS baseline (engine), Azure SQL Database, Power BI Embedded A2 capacity.\",\n    \"interServiceConnections\": \"Calls the shared Vantage Entitlement API for licensing checks.\",\n    \"externalDependencies\": \"Azure AD B2C, Azure Key Vault, Datadog, Power BI Embedded.\"\n  },\n  \"decisionRecords\": [\n    {\n      \"ref\": \"MEKHRF9KYX-TCWC\",\n      \"key\": \"noApplicablePattern\"\n    }\n  ],\n  \"networkZones\": [\n    {\n      \"id\": \"app\",\n      \"name\": \"Application\",\n      \"tier\": \"application\",\n      \"description\": \"AKS-hosted Cost of Service engine pods.\"\n    },\n    {\n      \"id\": \"data\",\n      \"name\": \"Data\",\n      \"tier\": \"data\",\n      \"description\": \"Azure SQL Database, private endpoint only.\"\n    },\n    {\n      \"id\": \"reporting\",\n      \"name\": \"Reporting\",\n      \"tier\": \"presentation\",\n      \"description\": \"Power BI Embedded capacity, accessed by internal users, regulators, and outside counsel via scoped reporting role.\"\n    }\n  ],\n  \"serviceGroups\": [\n    {\n      \"name\": \"Application\",\n      \"deploymentTarget\": \"H1ZTZXV5F6-C1CZ\",\n      \"deployableObjects\": [\n        {\n          \"ref\": \"Y1C3JYAM8E-J7PG\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"application\",\n          \"intent\": \"ha\",\n          \"notes\": \"2-4 replicas.\"\n        },\n        {\n          \"ref\": \"ZV0QNH8M3D-EYW8\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"application\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Identity & Access service.\"\n        },\n        {\n          \"ref\": \"37AJ772M7W-V27N\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"utility\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Secrets Management service.\"\n        },\n        {\n          \"ref\": \"FH8VD6HQ69-ZMEG\",\n          \"networkZone\": \"app\",\n          \"diagramTier\": \"utility\",\n          \"intent\": \"ha\",\n          \"notes\": \"Shared Observability service.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Data\",\n      \"deploymentTarget\": \"azure-sql-database\",\n      \"deployableObjects\": [\n        {\n          \"ref\": \"W8Y50NQF1Z-4VW7\",\n          \"networkZone\": \"data\",\n          \"diagramTier\": \"data\",\n          \"intent\": \"ha\",\n          \"notes\": \"Zone-redundant; 10-year evidentiary retention handled out-of-band.\"\n        }\n      ]\n    },\n    {\n      \"name\": \"Reporting\",\n      \"deploymentTarget\": \"power-bi-embedded\",\n      \"deployableObjects\": [\n        {\n          \"ref\": \"4MNRK1XQZ7-PB10\",\n          \"networkZone\": \"reporting\",\n          \"diagramTier\": \"presentation\",\n          \"intent\": \"standalone\",\n          \"notes\": \"Managed PaaS capacity; no replica/HA concept independently modeled.\"\n        }\n      ]\n    }\n  ],\n  \"_source\": \"catalog/engineering/software-deployment-patterns/regulatory/sdp.yaml\"\n}",
      "existsInCatalog": true,
