      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"H1ZTZXV5F6-C1CZ\",\n  \"type\": \"host\",\n  \"name\": \"Shared AKS Node Pool Baseline\",\n  \"description\": \"The common AKS node pool configuration (OS image, VM size, ingress-nginx, cert-manager, Datadog DaemonSet) that Infra & DevOps publishes as a Terraform module and that every product team's own cluster is built from. This Host object models that baseline, not any one product's specific cluster instance.\\n\",\n  \"version\": \"1.0.0\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"infra-devops\",\n    \"contact\": \"infra-devops@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"host\",\n    \"kubernetes\",\n    \"shared-service\"\n  ],\n  \"notes\": {\n    \"externalInteractionRationales\": {\n      \"Authentication Platform\": \"Node-level Azure AD-integrated RBAC; no local Kubernetes users exist.\",\n      \"Logging Service\": \"Container and node logs forwarded via the Datadog Agent DaemonSet rather than Azure Monitor directly, to keep one log pipeline of record.\",\n      \"Monitoring Service\": \"Datadog Kubernetes integration is the single source of node and pod health for every product cluster.\",\n      \"Security Monitoring Service\": \"Datadog Cloud Security Management scans node and container configuration against CIS Kubernetes Benchmark.\",\n      \"Patch Management Platform\": \"AKS node image auto-upgrade channel set to NodeImage, applying OS and kubelet patches on a weekly maintenance window.\"\n    },\n    \"internalComponentRationales\": {\n      \"Ubuntu 22.04 LTS\": \"Standard AKS-supported node OS image.\",\n      \"Azure Standard_D-series v5 VM\": \"General-purpose compute tier sized for typical product workloads; teams with different profiles (Data & Analytics' Spark workers) override the node pool VM size in their own infra/ but inherit this baseline module otherwise.\"\n    }\n  },\n  \"operatingSystemComponent\": \"C657R8CNHY-FDK6\",\n  \"computePlatformComponent\": \"WBCN4NVAYG-RFC8\",\n  \"internalComponents\": [\n    {\n      \"ref\": \"C657R8CNHY-FDK6\",\n      \"role\": \"os\"\n    },\n    {\n      \"ref\": \"WBCN4NVAYG-RFC8\",\n      \"role\": \"hardware\"\n    }\n  ],\n  \"externalInteractions\": [\n    {\n      \"name\": \"Authentication Platform\",\n      \"notes\": \"Azure AD-integrated Kubernetes RBAC; no local cluster users.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-MHJM\"\n      ]\n    },\n    {\n      \"name\": \"Logging Service\",\n      \"notes\": \"Datadog Agent DaemonSet collects and forwards container and node logs.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-D04B\"\n      ]\n    },\n    {\n      \"name\": \"Monitoring Service\",\n      \"notes\": \"Datadog Kubernetes integration tracks node and pod health.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-98VD\"\n      ]\n    },\n    {\n      \"name\": \"Security Monitoring Service\",\n      \"notes\": \"Datadog Cloud Security Management benchmarks node and container configuration.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-JW52\"\n      ]\n    },\n    {\n      \"name\": \"Patch Management Platform\",\n      \"notes\": \"AKS NodeImage auto-upgrade channel on a weekly maintenance window.\",\n      \"capabilities\": [\n        \"01KQQ4Q026-BH6E\"\n      ]\n    }\n  ],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-THYN\",\n    \"8SEDYZHP49-YJHQ\",\n    \"2EZZ268XWW-B5TP\",\n    \"P6M8FWV2D8-0RM8\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"4EEW7MZ0YX-DFWJ\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"2EZZ268XWW-B5TP\",\n      \"requirementId\": \"VM-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"ref\": \"4EEW7MZ0YX-DFWJ\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/hosts/host-aks-shared-node-pool.yaml\"\n}",
      "existsInCatalog": true,
