      "notes": {
        "serviceAuthentication": "Administrators authenticate to the Azure AD B2C admin portal via Acme corporate Azure AD with mandatory MFA (Conditional Access policy CA-12); no shared admin accounts exist.",
        "secretsManagement": "Custom policy signing keys and client secrets are stored in the Core Platform Azure Key Vault and rotated every 90 days by an automated runbook.",
        "serviceLogging": "Sign-in and audit logs stream to the Core Platform Log Analytics workspace via Azure AD B2C diagnostic settings, then forward to the company-wide Datadog log pipeline (see Observability shared service).",
        "healthWelfareMonitoring": "Azure Monitor alerts on sign-in failure rate and custom policy execution latency; surfaced on the Core Platform Datadog dashboard.",
        "availabilityModel": "Microsoft-operated multi-region active-active service; Acme PowerSoft has no failover responsibility, target availability tracked against Microsoft's 99.9% Azure AD B2C SLA.",
        "scalabilityModel": "Fully elastic, vendor-managed; Core Platform monitors monthly active user (MAU) consumption against the licensed tier.",
        "recoverabilityModel": "Vendor-managed; Core Platform's only recovery responsibility is custom policy and key restoration from the policies Git repository and Key Vault soft-delete/purge protection.",
        "failureDomain": "An outage affects sign-in and token issuance for every Acme PowerSoft product simultaneously; cached tokens continue to authorize existing sessions until expiry.",
        "externalInteractionRationales": {
          "Service Monitoring": "Routed through the shared Observability runtime service rather than a bespoke dashboard, consistent with the Infra & DevOps observability baseline."
        },
        "internalComponentRationales": {
          "Azure AD B2C": "Sole internal component; this is a fully PaaS-delivered identity provider with no self-managed compute."
        }
      },
