      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"FH8VD6HQ69-ZMEG\",\n  \"type\": \"runtime_service\",\n  \"name\": \"Observability Platform (Datadog)\",\n  \"description\": \"Company-wide metrics, logs, and APM trace aggregation. Every other shared service's \\\"Service Monitoring\\\" external interaction in this catalog resolves here.\",\n  \"version\": \"1.0.0\",\n  \"deliveryModel\": \"saas\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"infra-devops\",\n    \"contact\": \"infra-devops@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"runtime\",\n    \"observability\",\n    \"shared-service\"\n  ],\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"792738MBB6-8XMK\",\n  \"notes\": {\n    \"serviceAuthentication\": \"Datadog org access is federated through Azure AD SSO; per-user API keys are disabled org-wide in favor of scoped service account keys reviewed quarterly.\",\n    \"secretsManagement\": \"Datadog API and APP keys are stored in the Infra & DevOps Key Vault and injected into agent DaemonSets via CSI secrets store driver, never baked into images.\",\n    \"serviceLogging\": \"Datadog's own platform audit log (who changed which monitor/dashboard) is itself a paid add-on enabled for this account and exported to the AU-01 retention archive.\",\n    \"healthWelfareMonitoring\": \"Datadog monitors its own agent fleet health (agent-not-reporting monitor); paged to Infra & DevOps on-call if more than 5% of agents go dark for 15 minutes.\",\n    \"availabilityModel\": \"Vendor SaaS, multi-region; Acme PowerSoft has no infrastructure responsibility, tracked against Datadog's published status page SLA.\",\n    \"scalabilityModel\": \"Per-host/per-container pricing tier scaled automatically as AKS node pools scale; reviewed monthly against the Infra & DevOps cloud cost budget.\",\n    \"recoverabilityModel\": \"Dashboards and monitors are defined as code (this repo's dashboards/ directory, mirrored from each product repo) and can be reapplied via the Datadog Terraform provider if the SaaS account configuration were ever lost.\",\n    \"failureDomain\": \"An outage degrades visibility into every other shared service and product, but does not itself take production traffic down -- it is purely an observability dependency, not a request-path dependency.\",\n    \"externalInteractionRationales\": {},\n    \"internalComponentRationales\": {}\n  },\n  \"internalComponents\": [\n    {\n      \"ref\": \"792738MBB6-8XMK\",\n      \"role\": \"function\"\n    }\n  ],\n  \"externalInteractions\": [],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-K5DR\",\n    \"P6M8FWV2D8-0RM8\",\n    \"KZM0T9NY43-3H8K\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"J1Z5VNP4K4-1Y6V\",\n      \"key\": \"serviceLogging\"\n    },\n    {\n      \"ref\": \"9M10QY0RXW-YRF2\",\n      \"key\": \"availabilityModel\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"P6M8FWV2D8-0RM8\",\n      \"requirementId\": \"AU-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"serviceLogging\",\n      \"ref\": \"J1Z5VNP4K4-1Y6V\"\n    },\n    {\n      \"requirementGroup\": \"KZM0T9NY43-3H8K\",\n      \"requirementId\": \"SLA-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"availabilityModel\",\n      \"ref\": \"9M10QY0RXW-YRF2\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/runtime-services/rs-observability.yaml\"\n}",
