      "detail": "{\n  \"schemaVersion\": \"1.0\",\n  \"uid\": \"SP7JGWQ9Z3-DR4F\",\n  \"type\": \"data_store_service\",\n  \"name\": \"Cross-Product Raw Landing Zone (ADLS Gen2)\",\n  \"description\": \"Shared object storage landing zone for raw data extracted from every product's operational database before it is transformed and loaded into the Snowflake warehouse. Modeled as a catalog-level shared service rather than left implicit inside the Insight Hub product repo.\\n\",\n  \"version\": \"1.0.0\",\n  \"deliveryModel\": \"paas\",\n  \"catalogStatus\": \"complete\",\n  \"lifecycleStatus\": \"active\",\n  \"owner\": {\n    \"team\": \"data-analytics\",\n    \"contact\": \"data-analytics@acmepowersoft.example.com\"\n  },\n  \"tags\": [\n    \"data-at-rest\",\n    \"shared-service\"\n  ],\n  \"host\": null,\n  \"primaryTechnologyComponent\": \"5JMBH216ND-AJE9\",\n  \"notes\": {\n    \"serviceAuthentication\": \"Airflow worker pods authenticate via Azure AD workload identity scoped to read/write on their own product's partition prefix only.\",\n    \"secretsManagement\": \"No static account keys are distributed; workload identity tokens are short-lived and Azure AD-issued.\",\n    \"serviceLogging\": \"Storage diagnostic logs (read/write/list operations) stream to Datadog log management.\",\n    \"healthWelfareMonitoring\": \"Datadog Azure Storage integration tracks ingress/egress volume and 4xx/5xx rates per container.\",\n    \"availabilityModel\": \"Zone-redundant storage (ZRS) in East US 2; tracked against Microsoft's published ADLS Gen2 SLA.\",\n    \"scalabilityModel\": \"Effectively unbounded object storage; no manual scaling action required.\",\n    \"recoverabilityModel\": \"Soft-delete enabled with a 14-day retention window; raw data is also re-derivable by re-running the source product's extraction job if a partition were lost, so this is treated as a cache of extraction, not a sole system of record.\",\n    \"failureDomain\": \"An outage blocks new raw-data landing and the nightly ELT load, but does not affect any product's operational database.\",\n    \"backup\": {\n      \"strategy\": \"Soft-delete (14-day) plus re-extraction from source-of-record on the rare case data is lost outright.\",\n      \"rto\": \"8 hours (re-run extraction DAGs for the affected partition)\",\n      \"rpo\": \"24 hours (one missed nightly load)\"\n    },\n    \"ha\": {\n      \"mechanism\": \"Zone-redundant storage (ZRS).\"\n    },\n    \"encryption\": {\n      \"atRest\": \"AES-256, Microsoft-managed keys.\"\n    },\n    \"accessControl\": {\n      \"model\": \"Azure AD workload identity, partition-prefix-scoped per product.\"\n    },\n    \"externalInteractionRationales\": {},\n    \"internalComponentRationales\": {}\n  },\n  \"internalComponents\": [\n    {\n      \"ref\": \"5JMBH216ND-AJE9\",\n      \"role\": \"function\"\n    }\n  ],\n  \"externalInteractions\": [],\n  \"requirementGroups\": [\n    \"01KQQ4Q027-VBF0\",\n    \"1JGV5Y25KN-73W7\",\n    \"8SEDYZHP49-YJHQ\"\n  ],\n  \"decisionRecords\": [\n    {\n      \"ref\": \"R07JQGMBBY-6B8S\",\n      \"key\": \"recoverabilityModel\"\n    },\n    {\n      \"ref\": \"9H6CA4N2A8-VZ8G\",\n      \"key\": \"serviceAuthentication\"\n    }\n  ],\n  \"requirementImplementations\": [\n    {\n      \"requirementGroup\": \"1JGV5Y25KN-73W7\",\n      \"requirementId\": \"DR-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"recoverabilityModel\",\n      \"ref\": \"R07JQGMBBY-6B8S\"\n    },\n    {\n      \"requirementGroup\": \"8SEDYZHP49-YJHQ\",\n      \"requirementId\": \"AC-01\",\n      \"status\": \"satisfied\",\n      \"mechanism\": \"decisionRecord\",\n      \"key\": \"serviceAuthentication\",\n      \"ref\": \"9H6CA4N2A8-VZ8G\"\n    }\n  ],\n  \"_source\": \"catalog/shared-services/data-store-services/ds-landing-zone.yaml\"\n}",
